import React from 'react';
import { useNavigate } from 'react-router-dom';
import logo from './assets/logo.png';
import { isAdmin, readUser } from './constants';

function Home() {
  const navigate = useNavigate();
  const user = readUser();
  const canSeeBi = isAdmin(user);

  return (
    <main className="app-page">
      <header className="topbar">
        <div className="brand-mark">
          <img src={logo} alt="GRC Consultoria Empresarial" />
        </div>

        <nav className="top-actions" aria-label="Navegação principal">
          <button className="ghost-action" onClick={() => navigate('/cadastro')}>
            Cadastrar reclamação
          </button>
          <button className="ghost-action" onClick={() => navigate('/gestao')}>
            Dashboard e gestão
          </button>
          {canSeeBi && (
            <button className="ghost-action" onClick={() => navigate('/bi')}>
              BI administrador
            </button>
          )}
          <button
            className="outline-action"
            onClick={() => {
              localStorage.removeItem('token');
              localStorage.removeItem('user');
              navigate('/');
            }}
          >
            Sair
          </button>
        </nav>
      </header>

      <section className="home-hero">
        <div className="home-copy">
          <p className="eyebrow">Sistema GRC</p>
          <h1>Gestão profissional de reclamações odontológicas.</h1>
          <p>
            Registre demandas, acompanhe a tratativa por operador e visualize os
            indicadores que orientam qualidade, atendimento e experiência do paciente.
          </p>
        </div>

        <div className="home-actions">
          <button className="primary-action" onClick={() => navigate('/cadastro')}>
            Nova reclamação
          </button>
          <button className="secondary-action" onClick={() => navigate('/gestao')}>
            Abrir dashboard e gestão
          </button>
        </div>
      </section>

      <section className="quick-grid" aria-label="Atalhos operacionais">
        <article className="quick-card">
          <span className="quick-number">01</span>
          <h2>Cadastro padronizado</h2>
          <p>Tipos de reclamação, clínica, canal, serviço envolvido e anexos.</p>
        </article>

        <article className="quick-card">
          <span className="quick-number">02</span>
          <h2>Gestão de tratativas</h2>
          <p>Comentários do operador, status e fechamento da reclamação.</p>
        </article>

        <article className="quick-card">
          <span className="quick-number">03</span>
          <h2>Indicadores executivos</h2>
          <p>Volume por tipo, clínica, cidade, estado e região.</p>
        </article>
      </section>
    </main>
  );
}

